mapper.select:
SELECT lecture_id, content_id, tenant_id, content_order, lecture_content_title, lecture_content_desc, reg_dt, upd_dt
FROM tb_lecture_content
WHERE lecture_id = #{lectureId}
AND tenant_id = #{tenantId}
ORDER BY content_order ASC, reg_dt DESC

SELECT lecture_id, content_id, tenant_id, content_order, lecture_content_title, lecture_content_desc, reg_dt, upd_dt
FROM tb_lecture_content
WHERE content_id = #{contentId}
AND tenant_id = #{tenantId}
ORDER BY content_order ASC, reg_dt DESC

SELECT lecture_id, content_id, tenant_id, content_order, lecture_content_title, lecture_content_desc, reg_dt, upd_dt
FROM tb_lecture_content
