mapper.update:
UPDATE tb_lecture_content
SET content_order = #{contentOrder},
    lecture_content_title = #{lectureContentTitle},
    lecture_content_desc = #{lectureContentDesc},
    upd_dt = NOW()
WHERE lecture_id = #{lectureId}
AND content_id = #{contentId}
AND tenant_id = #{tenantId}

